import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as r,e as s}from"./app-ef36cc2e.js";const t={},l=s('<h1 id="面试-mysql" tabindex="-1"><a class="header-anchor" href="#面试-mysql" aria-hidden="true">#</a> 面试-MySQL</h1><h3 id="日常工作中怎么优化sql" tabindex="-1"><a class="header-anchor" href="#日常工作中怎么优化sql" aria-hidden="true">#</a> 日常工作中怎么优化SQL</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：日常工作中怎么优化SQL</b></summary><p><b style="color:#f19977;">答：加索引<br>减少返回的数据列<br>避免走全表扫描、避免子查询<br>分库分表</b></p></details><h3 id="mysql为什么使用b-tree作为索引结构" tabindex="-1"><a class="header-anchor" href="#mysql为什么使用b-tree作为索引结构" aria-hidden="true">#</a> MySQL为什么使用B+Tree作为索引结构</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：MySQL为什么使用B+Tree作为索引结构</b></summary><p><b style="color:#f19977;">答：B树是一种多路平衡树，用其存储大量数据，整个树的高度相比二叉树来说会矮很多。树的高度决定磁盘IO的次数，树越矮，次数越少就越快。<br>相比较与B树，B+Tree所有的数据都存储在叶子节点并且使用双向链表的方式进行关联，非叶子节点只存储索引。B+Tree非叶子节点不存储数据，所以每一层能够存储的索引数量会增加，意味着B+树在层高相同的情况下存储的数据量要比B树要多，使得磁盘IO次数更少。<br>在MySQL里面，范围查询是一个比较常用的操作，而B+Tree的所有存储在叶子节点的数据使用了双向链表来关联，所以在查询的时候只需查两个节点进行遍历就行，而B树需要获取所有节点，所以B+Tree在范围查询上效率更高。<br>因为B+Tree叶子节点存储所有数据，所以B+Tree的全局扫描能力更强一些，因为它只需要扫描叶子节点。但是B树需要遍历整个树。</b></p></details><h3 id="数据库连接池有什么用" tabindex="-1"><a class="header-anchor" href="#数据库连接池有什么用" aria-hidden="true">#</a> 数据库连接池有什么用</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：数据库连接池有什么用</b></summary><p><b style="color:#f19977;">答：首先，数据库连接池是一种池化技术，池化技术的核心思想是实现资源的复用，避免资源重复创建销毁的开销。而在数据库的应用场景里面，应用程序每次向数据库发起CRUD操作的时候，都需要创建连接。在数据库访问量较大的情况下，频繁的创建连接会带来较大的性能开销。而连接池的核心思想，就是应用程序在启动的时候提前初始化一部分连接保存到连接池里面，当应用需要使用连接的时候，直接从连接池获取一个已经建立好的链接。避免了每次连接的建立和释放带来的开销。</b></p></details><h3 id="数据库连接池有哪些关键参数" tabindex="-1"><a class="header-anchor" href="#数据库连接池有哪些关键参数" aria-hidden="true">#</a> 数据库连接池有哪些关键参数</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：数据库连接池有哪些关键参数</b></summary><p><b style="color:#f19977;">答：初始化连接数、最大连接数、最大空闲连接数、最小空闲连接、最大等待时间、无效连接清除</b></p></details>',9),i=[l];function d(c,o){return a(),r("div",null,i)}const b=e(t,[["render",d],["__file","面试-MySQL.html.vue"]]);export{b as default};
